class SovereignQuantizer(nn.Module):
    def forward(self, x, force_hard=False):
        step = torch.clamp(self.step_size, min=1e-4)
        if self.training and not force_hard:
            # Soft quantization: add uniform noise
            noise = torch.rand_like(x) - 0.5
            return x + noise * step, step
        else:
            # Hard quantization with STE
            return STEQuantize.apply(x, step), step

class ResidualRefinementNetwork(nn.Module):
    def forward(self, recon, orig=None):
        if orig is None:
            orig = recon.detach()
        x = torch.cat([recon, orig], dim=1)
        res = self.net(x)
        return recon + res
